// Extraer datos del payload enviado por trigger-sdk-sync.yml
var body = items[0].json.body || items[0].json;
var specHash = body.spec_hash || 'unknown';
var triggeredBy = body.triggered_by || 'github-actions';
var timestamp = new Date().toISOString();

console.log('[SDK Sync] Triggered by: ' + triggeredBy);
console.log('[SDK Sync] Spec hash: ' + specHash);
console.log('[SDK Sync] Timestamp: ' + timestamp);

return [{ json: { specHash: specHash, triggeredBy: triggeredBy, timestamp: timestamp } }];

// Decodificar spec3.sdk.yaml (GitHub retorna base64)
var fileData = items[0].json;
var specContent = Buffer.from(fileData.content, 'base64').toString('utf-8');
var fileSha = fileData.sha;

// Lista de SDK repos de MercadoPago
// TODO: confirmar nombres exactos de los repos SDK de MP
var sdkRepos = [
  { name: 'sdk-java',       specPath: 'openapi/spec3.yaml', lang: 'Java' },
  { name: 'sdk-python',     specPath: 'openapi/spec3.yaml', lang: 'Python' },
  { name: 'sdk-nodejs',     specPath: 'openapi/spec3.yaml', lang: 'Node.js' },
  { name: 'sdk-php',        specPath: 'openapi/spec3.yaml', lang: 'PHP' },
  { name: 'sdk-ruby',       specPath: 'openapi/spec3.yaml', lang: 'Ruby' },
  { name: 'sdk-dotnet',     specPath: 'openapi/spec3.yaml', lang: '.NET' },
  { name: 'sdk-go',         specPath: 'openapi/spec3.yaml', lang: 'Go' }
];

return sdkRepos.map(function(sdk) {
  return {
    json: {
      repoName: sdk.name,
      specPath: sdk.specPath,
      lang: sdk.lang,
      specContent: specContent,
      specContentBase64: fileData.content,
      fileSha: fileSha
    }
  };
});

var specItem   = $node['Preparar lista de SDK repos'].item.json;
var mainShaData = items[0].json;
var mainSha = mainShaData.object.sha;

var crypto = require('crypto');
var hash = crypto.createHash('sha256')
  .update(specItem.specContent)
  .digest('hex')
  .slice(0, 8);

var branch = 'enhancement/automatic-spec-openapi/spec3-sdk-' + hash;
var commitMsg = 'chore(spec): update SDK spec from fury_openapi\n\nSpec hash: ' + hash + '\nTriggered by: openapi sync pipeline';

return [{ json: {
  repoName:           specItem.repoName,
  specPath:           specItem.specPath,
  lang:               specItem.lang,
  specContentBase64:  specItem.specContentBase64,
  mainSha:            mainSha,
  branch:             branch,
  commitMsg:          commitMsg,
  hash:               hash
} }];

var item = $node['Construir nombre de rama y commit'].item.json;
console.log('[SDK Sync] ✅ ' + item.lang + ' (' + item.repoName + ') → branch: ' + item.branch);
return [{ json: { success: true, repo: item.repoName, branch: item.branch, lang: item.lang } }];
